class SummaryRanges {
public:
    SummaryRanges() {

    }

    void addNum(int value) {
        auto it = intervals.lower_bound(value);
        if (it != intervals.begin() && (*std::prev(it))[1] + 1 == value) {
            (*std::prev(it))[1] = value;
        } else if (it != intervals.end() && (*it)[0] - 1 == value) {
            (*it)[0] = value;
            if (it != intervals.begin() && (*std::prev(it))[1] + 1 == (*it)[0]) {
                (*std::prev(it))[1] = (*it)[1];
                intervals.erase(it);
            }
        } else {
            intervals.insert(it, {value, value});
        }
    }

    vector<vector<int>> getIntervals() {
        vector<vector<int>> result(intervals.begin(), intervals.end());
        return result;
    }
private:
    set<vector<int>> intervals;
};

